import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import IndexPage from './pages/IndexPage';
import AdminPage from './pages/AdminPage';
import HomePage from './pages/HomePage';
import Page from './pages/Page';

function App() {
  const [isDbInitialized, setIsDbInitialized] = useState(false); // État pour surveiller l'initialisation

  useEffect(() => {
    const initializeDatabase = async () => {
      try {
        const response = await fetch('http://127.0.0.1:5000/api/init_db');
        if (!response.ok) {
          throw new Error(HTTP error! Status: ${response.status});
        }
        const data = await response.json();
        console.log('Base de données initialisée:', data);
        setIsDbInitialized(true); // Mise à jour de l'état après l'initialisation
      } catch (error) {
        console.error("Erreur lors de l'initialisation de la base de données :", error);
      }
    };

    initializeDatabase();
  }, []);

  // Afficher un indicateur de chargement tant que la base de données n'est pas prête
  if (!isDbInitialized) {
    return <div>Initialisation de l'application en cours...</div>;
  }

  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/admin" element={<AdminPage />} />
        {/* Route par défaut pour capturer toutes les autres URLs */}
        <Route path="/:pageKey" element={<Page />} />
        <Route path="*" element={<IndexPage />} />
      </Routes>
    </Router>
  );
}

export default App;

